import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './PreviewPage.css';

function PreviewPage() {
  const location = useLocation();
  const navigate = useNavigate();
  const [previewData, setPreviewData] = useState(null);
  const [selectedSheet, setSelectedSheet] = useState(0);
  const [resultId, setResultId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortedSheets, setSortedSheets] = useState([]);

  useEffect(() => {
    if (location.state && location.state.previewData) {
      setPreviewData(location.state.previewData);
      setResultId(location.state.resultId);
      
      // Sort sheets by row count (descending)
      const sorted = [...location.state.previewData.sheets].sort((a, b) => 
        b.data.length - a.data.length
      );
      setSortedSheets(sorted);
    } else {
      // If no data, redirect back to home
      navigate('/');
    }
  }, [location, navigate]);

  const handleDownload = async () => {
    try {
      const response = await axios.post('http://localhost:3001/excel/download', 
        { resultId },
        { responseType: 'blob' }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'filtered_results.xlsx');
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (error) {
      alert('Error downloading file: ' + error.message);
    }
  };

  const handleDownloadSheet = async (sheetIndex) => {
    try {
      const response = await axios.post('http://localhost:3001/excel/download-sheet', 
        { resultId, sheetIndex },
        { responseType: 'blob' }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `${previewData.sheets[sheetIndex].name}.xlsx`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (error) {
      alert('Error downloading sheet: ' + error.message);
    }
  };

  const handleSheetChange = (e) => {
    const sheetName = e.target.value;
    const index = previewData.sheets.findIndex(sheet => sheet.name === sheetName);
    setSelectedSheet(index);
  };

  // Filter sheets based on search term
  const filteredSheets = sortedSheets.filter(sheet => 
    sheet.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (sheet.subId && sheet.subId.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  if (!previewData) {
    return <div>Loading...</div>;
  }

  return (
    <div className="preview-page">
      <div className="preview-container">
        <div className="preview-header">
          <button className="back-btn" onClick={() => navigate('/')}>
            ← Back to Upload
          </button>
          <h1>Preview Results</h1>
        </div>

        <div className="download-all-section">
          <button type="button" className="download-all-btn" onClick={handleDownload}>
            📥 Download All Sheets (Excel File)
          </button>
        </div>

        <div className="sheet-selector-section">
          <div className="search-box">
            <input
              type="text"
              placeholder="🔍 Search by SubID or Sheet Name..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="search-input"
            />
          </div>

          <div className="dropdown-section">
            <label>Select Sheet to Preview:</label>
            <select 
              value={previewData.sheets[selectedSheet]?.name || ''} 
              onChange={handleSheetChange}
              className="sheet-dropdown"
            >
              {filteredSheets.map((sheet, index) => (
                <option key={index} value={sheet.name}>
                  {sheet.name} ({sheet.data.length} rows)
                </option>
              ))}
            </select>
          </div>
        </div>
        
        <div className="sheet-preview">
          <div className="sheet-header">
            <div className="sheet-info">
              <h3>{previewData.sheets[selectedSheet]?.name}</h3>
              <span className="row-count">
                {previewData.sheets[selectedSheet]?.data.length} rows
              </span>
            </div>
            <button 
              type="button" 
              className="download-sheet-btn" 
              onClick={() => handleDownloadSheet(selectedSheet)}
            >
              📥 Download This Sheet
            </button>
          </div>

          <div className="table-container">
            <table>
              <thead>
                <tr>
                  {previewData.sheets[selectedSheet] && 
                   previewData.sheets[selectedSheet].data.length > 0 &&
                    Object.keys(previewData.sheets[selectedSheet].data[0]).map((key) => (
                      <th key={key}>{key}</th>
                    ))}
                </tr>
              </thead>
              <tbody>
                {previewData.sheets[selectedSheet] && 
                 previewData.sheets[selectedSheet].data.map((row, idx) => (
                  <tr key={idx}>
                    {Object.values(row).map((value, i) => (
                      <td key={i}>{String(value)}</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

export default PreviewPage;
